code.C:
#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        long long X, Y; scanf("%lld %lld", &X, &Y);
        long long newRating = X + Y;
        if (newRating >= 2000) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

